Code.Terraform:
```hcl
resource "aws_iam_policy" "example_resource" {
  name = "scoped-marketplace-subscribe"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["aws-marketplace:Subscribe"]
      # CRITICAL: scope to specific product ARNs instead of "*"
      Resource = ["arn:aws:aws-marketplace::123456789012:product/example-product-id"]
    }]
  })
}
```
